









import React, { useState } from 'react';
// TD-030f: ESM imports — tabs + ErrorBoundary.
import { YamlValidatorTab } from './YamlValidatorTab.jsx';
import { AlertPreviewTab } from './AlertPreviewTab.jsx';
import { RoutingTraceTab } from './RoutingTraceTab.jsx';
// PR-portal-11: each tab gets its own boundary so a bad render in
// one tab doesn't crash the others. Loader-level boundary
// (PR-portal-2) catches whole-tool failures; this is a per-tab
// safety net for the multi-tab tools.
import { ErrorBoundary } from './_common/components/ErrorBoundary.jsx';

const t = window.__t || ((zh, en) => en);

/* ── Main Portal Component ── */
const TABS = [
  { id: 'validate', label: () => t('YAML 驗證', 'YAML Validation'), icon: '🔍' },
  { id: 'alerts', label: () => t('告警預覽', 'Alert Preview'), icon: '🔔' },
  { id: 'routing', label: () => t('路由追蹤', 'Routing Trace'), icon: '🌐' },
];

export default function SelfServicePortal() {
  const [activeTab, setActiveTab] = useState('validate');

  return (
    <div className="max-w-4xl mx-auto">
      <div className="mb-6">
        <h1 className="text-2xl font-bold text-gray-900">
          {t('租戶自助入口', 'Tenant Self-Service Portal')}
        </h1>
        <p className="text-gray-600 mt-1">
          {t('驗證配置、預覽告警、追蹤路由 — 無需 CLI 或部署。支援 15 個 Rule Pack、四層路由合併 (ADR-007)、Severity Dedup。',
             'Validate configs, preview alerts, trace routing — no CLI or deployment needed. Supports 15 Rule Packs, four-layer routing merge (ADR-007), severity dedup.')}
        </p>
      </div>

      {/* Tabs */}
      <div className="flex gap-1 bg-gray-100 p-1 rounded-lg mb-6">
        {TABS.map(tab => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id)}
            className={`flex-1 px-3 py-2 rounded-md text-sm font-medium transition-colors ${
              activeTab === tab.id
                ? 'bg-white text-blue-600 shadow-sm'
                : 'text-gray-600 hover:text-gray-800'
            }`}
          >
            <span className="mr-1">{tab.icon}</span>
            {tab.label()}
          </button>
        ))}
      </div>

      {/* Tab content — PR-portal-11: per-tab subtree boundaries so a
          render error in one tab doesn't crash the sibling tabs. */}
      <div className="bg-white rounded-lg border p-6">
        {activeTab === 'validate' && (
          <ErrorBoundary scope="self-service-portal/tab/validate">
            <YamlValidatorTab />
          </ErrorBoundary>
        )}
        {activeTab === 'alerts' && (
          <ErrorBoundary scope="self-service-portal/tab/alerts">
            <AlertPreviewTab />
          </ErrorBoundary>
        )}
        {activeTab === 'routing' && (
          <ErrorBoundary scope="self-service-portal/tab/routing">
            <RoutingTraceTab />
          </ErrorBoundary>
        )}
      </div>

      {/* Footer info */}
      <div className="mt-6 p-4 bg-blue-50 rounded-lg border border-blue-100">
        <h4 className="text-sm font-medium text-blue-800 mb-2">
          {t('提示', 'Tips')}
        </h4>
        <ul className="text-sm text-blue-700 space-y-1">
          <li>{t('• 此工具在瀏覽器端執行，YAML 不會送往任何伺服器。',
                 '• This tool runs entirely in your browser — YAML is never sent to any server.')}</li>
          <li>{t('• 工具自動載入 platform-data.json 中的 15 個 Rule Pack metric 定義。',
                 '• Tool auto-loads 15 Rule Pack metric definitions from platform-data.json.')}</li>
          <li>{t('• 完整驗證請使用 CLI: da-tools validate-config --config-dir conf.d/',
                 '• For full validation use CLI: da-tools validate-config --config-dir conf.d/')}</li>
          <li>{t('• Policy-as-Code 策略需透過 CLI 評估: da-tools evaluate-policy --config-dir conf.d/',
                 '• Policy-as-Code evaluation via CLI: da-tools evaluate-policy --config-dir conf.d/')}</li>
        </ul>
      </div>
    </div>
  );
}
